form.script:
document.addEventListener("DOMContentLoaded", function() {
    var btnConfirm = document.getElementById('btn-confirm-book');
    var btnMerge = document.getElementById('btn-merge-seats');
    var form = document.getElementById('booking_form');

    // Check for error=duplicate in URL
    if (window.location.search.includes("error=duplicate")) {
        $('#duplicateModal').modal('show');
        // Clean URL so refresh doesn't pop it again
        const url = new URL(window.location.href);
        url.searchParams.delete('error');
        window.history.replaceState({}, document.title, url.toString());
    }

    if (btnMerge && form) {
        btnMerge.addEventListener('click', function(e) {
            form.action = '/packages/book/merge_seats';
            form.submit();
        });
    }

    if (btnConfirm && form) {
        btnConfirm.addEventListener('click', function(e) {
            e.preventDefault();
            var calendarId = form.querySelector('input[name="calendar_id"]:checked');
            if (!calendarId) {
                form.reportValidity();
                return;
            }
            fetch('/packages/book/check_duplicate', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    jsonrpc: "2.0",
                    method: "call",
                    params: {
                        calendar_id: calendarId.value
                    }
                })
            })
            .then(response => response.json())
            .then(data => {
                if (data.result && data.result.is_duplicate) {
                    $('#duplicateModal').modal('show');
                } else {
                    form.submit();
                }
            })
            .catch(error => {
                console.error('Error:', error);
                form.submit();
            });
        });
    }
});

div.script:
document.addEventListener('DOMContentLoaded', function() {
    const radios = document.querySelectorAll('.date-radio');
    const displayDate = document.getElementById('display_date');
    const seatInputEl = document.getElementById('seat_input');

    radios.forEach(r => {
        r.addEventListener('change', function() {
            if(this.checked) {
                displayDate.textContent = this.getAttribute('data-display');
                if (seatInputEl) {
                    let maxSeats = parseInt(this.getAttribute('data-remaining-seats'));
                    let totalSeats = parseInt(this.getAttribute('data-total-seats'));
                    let bookedSeats = parseInt(this.getAttribute('data-booked-seats'));
                    seatInputEl.setAttribute('max', maxSeats);

                    const maxSeatsDisplay = document.getElementById('max_seats_display');
                    if (maxSeatsDisplay) {
                        maxSeatsDisplay.textContent = '(Booked: ' + bookedSeats + ' | Remaining: ' + maxSeats + ' | Total: ' + totalSeats + ' seats)';
                    }

                    let currentSeats = parseInt(seatInputEl.value);
                    currentSeats = Math.max(1, currentSeats || 1);
                    if (currentSeats !== Math.min(currentSeats, maxSeats)) {
                        seatInputEl.value = maxSeats;
                        seatInputEl.dispatchEvent(new Event('input'));
                    }
                }
            }
        });
    });

    const firstAvailable = document.querySelector('.date-radio:not([disabled])');
    if (firstAvailable) {
        firstAvailable.checked = true;
        firstAvailable.dispatchEvent(new Event('change'));
    }

    // Image Modal logic
    const galleryThumbnails = Array.from(document.querySelectorAll('.gallery-thumbnail'));
    const modalImage = document.getElementById('modalImage');
    let currentImageIndex = 0;

    function updateModalImage(index) {
        if (galleryThumbnails.length === 0) return;
        if (index === -1) index = galleryThumbnails.length - 1;
        if (index === galleryThumbnails.length) index = 0;
        currentImageIndex = index;
        modalImage.src = galleryThumbnails[index].getAttribute('data-image-src');
    }

    galleryThumbnails.forEach((thumb, index) => {
        thumb.addEventListener('click', function() {
            updateModalImage(index);
        });
    });

    const prevBtn = document.getElementById('prevImageBtn');
    const nextBtn = document.getElementById('nextImageBtn');

    if (prevBtn) {
        prevBtn.addEventListener('click', () => updateModalImage(currentImageIndex - 1));
    }
    if (nextBtn) {
        nextBtn.addEventListener('click', () => updateModalImage(currentImageIndex + 1));
    }

    document.addEventListener('keydown', function(e) {
        if (document.body.classList.contains('modal-open')) {
            if (e.key === 'ArrowLeft') {
                updateModalImage(currentImageIndex - 1);
            } else if (e.key === 'ArrowRight') {
                updateModalImage(currentImageIndex + 1);
            }
        }
    });

    // Seat Price Calculation
    const seatInput = document.getElementById('seat_input');
    const priceDisplay = document.getElementById('total_price_display');
    if (seatInput && priceDisplay) {
        seatInput.addEventListener('input', function() {
            let seats = parseInt(this.value);
            seats = Math.max(1, seats || 1); // Avoid XML less-than signs
            let maxSeats = parseInt(this.getAttribute('max'));
            if (!isNaN(maxSeats)) {
                seats = Math.min(seats, maxSeats);
                this.value = seats;
            }

            let unitPrice = parseFloat(priceDisplay.getAttribute('data-unit-price'));
            let symbol = priceDisplay.getAttribute('data-currency-symbol');
            let position = priceDisplay.getAttribute('data-currency-position');

            let total = (unitPrice * seats).toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2});

            if (position === 'after') {
                priceDisplay.textContent = total + ' ' + symbol;
            } else {
                priceDisplay.textContent = symbol + total;
            }
        });
    }
});

document.addEventListener("DOMContentLoaded", function() {
    var autoTab = document.getElementById('auto-tab');
    var qrTab = document.getElementById('qr-tab');
    var paymentMethodInput = document.getElementById('paymentMethodInput');
    if (autoTab && qrTab) {
        autoTab.addEventListener('shown.bs.tab', function (e) {
            paymentMethodInput.value = 'auto';
        });
        qrTab.addEventListener('shown.bs.tab', function (e) {
            paymentMethodInput.value = 'qr';
        });
    }
});

t.script:
document.addEventListener('DOMContentLoaded', function() {
    var calendarEl = document.getElementById('booking_calendar');
    if (!calendarEl) return;

    var eventsData = [];
    try {
        eventsData = JSON.parse(calendarEl.dataset.events || '[]');
    } catch (e) {
        console.error('Failed to parse events JSON', e);
    }

    if (typeof FullCalendar !== 'undefined') {
        var calendar = new FullCalendar.Calendar(calendarEl, {
            initialView: 'dayGridMonth',
            headerToolbar: {
                left: 'prev,next today',
                center: 'title',
                right: 'dayGridMonth,listMonth'
            },
            events: eventsData,
            eventClick: function(info) {
                info.jsEvent.preventDefault();

                var props = info.event.extendedProps;
                if (props) {
                    document.getElementById('modal_package_name').textContent = props.package_name;
                    document.getElementById('modal_date_range').textContent = props.date_range;
                    document.getElementById('modal_seats').textContent = props.seats;

                    var statusBadge = document.getElementById('modal_status');
                    statusBadge.textContent = props.status;
                    if (props.status === 'Confirmed') {
                        statusBadge.className = 'badge bg-success';
                    } else {
                        statusBadge.className = 'badge bg-warning text-dark';
                    }

                    document.getElementById('modal_booking_link').href = info.event.url;

                    $('#calendarBookingModal').modal('show');
                } else if (info.event.url) {
                    window.location.href = info.event.url;
                }
            }
        });
        calendar.render();
    } else {
        calendarEl.textContent = 'Error loading calendar library.';
    }
});
